jsxGraph.script:
board.suspendUpdate();
board.create('arrow', [[0,0], [0, 48000]], {strokeColor: 'black', strokeWidth: 1});
board.create('arrow', [[0,0], [600, 0]], {strokeColor: 'black', strokeWidth: 1});

board.create('text', [680, -3000, 't (hours)'], {anchorX: 'right', anchorY: 'top', fontSize: 14});
board.create('text', [-40, 52000, 'V (litres)'], {anchorX: 'right', anchorY: 'bottom', fontSize: 14});

board.create('segment', [[-15, 40000], [0, 40000]], {strokeColor: 'black', strokeWidth: 1});
board.create('text', [-20, 40000, '40000'], {anchorX: 'right', anchorY: 'middle', fontSize: 14});

board.create('segment', [[-15, 20000], [0, 20000]], {strokeColor: 'black', strokeWidth: 1});
board.create('text', [-20, 20000, '20000'], {anchorX: 'right', anchorY: 'middle', fontSize: 14});

board.create('segment', [[500, -1500], [500, 0]], {strokeColor: 'black', strokeWidth: 1});
board.create('text', [500, -3000, '500'], {anchorX: 'middle', anchorY: 'top', fontSize: 14});

var p = board.create('point', [500, 20000], {visible: false});
board.create('text', [520, 20000, '(500, 20000)'], {anchorX: 'left', anchorY: 'middle', fontSize: 14, cssClass: 'nowrap-text'});

var pStart = board.create('point', [0, 40000], {visible: false});
board.create('segment', [pStart, p], {strokeColor: 'blue', strokeWidth: 1.5});

board.create('segment', [[500,0], p], {strokeColor: 'red', strokeWidth: 1.5, dash: 2});

board.unsuspendUpdate();

board.suspendUpdate();
board.create('arrow', [[0,0], [0, 210]], {strokeColor: 'black', strokeWidth: 1});
board.create('arrow', [[0,0], [3.1, 0]], {strokeColor: 'black', strokeWidth: 1});

board.create('text', [3.4, -10, 't (hours)'], {anchorX: 'right', anchorY: 'top', fontSize: 14});
board.create('text', [-0.2, 230, 'd (km)'], {anchorX: 'right', anchorY: 'bottom', fontSize: 14});

var yTicks = [30, 120, 180];
yTicks.forEach(function(y) {
  board.create('segment', [[-0.05, y], [0, y]], {strokeColor: 'black', strokeWidth: 1});
  board.create('text', [-0.1, y, y.toString()], {anchorX: 'right', anchorY: 'middle', fontSize: 14});
});

var xTicks = [1.5, 2.5];
xTicks.forEach(function(x) {
  board.create('segment', [[x, -3], [x, 0]], {strokeColor: 'black', strokeWidth: 1});
  board.create('text', [x, -10, x.toString()], {anchorX: 'middle', anchorY: 'top', fontSize: 14});
});

var aStart = board.create('point', [0, 30], {visible: true, name: '', size: 2, color: 'red', label: {autoPosition: false, offset: [0, 10]}});
var aEnd = board.create('point', [2.5, 180], {visible: true, name: '', size: 2, color: 'red', label: {autoPosition: false, offset: [0, 10]}});
board.create('segment', [aStart, aEnd], {strokeColor: 'blue', strokeWidth: 1.5});
board.create('text', [2.5, 190, 'Car A'], {anchorX: 'middle', anchorY: 'bottom', fontSize: 14});

var bStart = board.create('point', [0, 120], {visible: true, name: '', size: 2, color: 'red', label: {autoPosition: false, offset: [0, 10]}});
var bEnd = board.create('point', [1.5, 0], {visible: true, name: '', size: 2, color: 'red', label: {autoPosition: false, offset: [0, 10]}});
board.create('segment', [bStart, bEnd], {strokeColor: 'blue', strokeWidth: 1.5});
board.create('text', [0.5, 20, 'Car B'], {anchorX: 'left', anchorY: 'bottom', fontSize: 14});

board.unsuspendUpdate();
